export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
  const runes = input.items.filter((item) => item.type === "rune");
  const nonRunes = input.items.filter((item) => item.type !== "rune");
  const nonRunesBase = nonRunes.reduce(
    (sum, item) => sum + BASE_PREMIUM_BY_ITEM_TYPE[item.type],
    0
  );
  const runesBase = runes.length === RUNE_BLOCK_SIZE
    ? RUNE_BLOCK_PRICE
    : runes.length * BASE_PREMIUM_BY_ITEM_TYPE.rune;
  return nonRunesBase + runesBase + PROCESSING_FEE;
}

