type Item = { type: string; material: string; enchantment: number; cursed: boolean };

const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_ITEM_TYPE[item.type];

const runeBaseFor = (runeCount: number): number =>
  runeCount === RUNE_BLOCK_SIZE
    ? RUNE_BLOCK_PRICE
    : runeCount * BASE_PREMIUM_BY_ITEM_TYPE.rune;

export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
  const runeCount = input.items.filter((item) => item.type === "rune").length;
  const nonRuneItemsBase = input.items
    .filter((item) => item.type !== "rune")
    .reduce((sum, item) => sum + basePremiumFor(item), 0);
  return nonRuneItemsBase + runeBaseFor(runeCount) + PROCESSING_FEE;
}
